patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 5907e2106533..680225af8278 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -6304,8 +6304,16 @@ static Value *simplifyUnaryIntrinsic(Function *F, Value *Op0,
   Value *X;
   switch (IID) {
   case Intrinsic::fabs:
-    if (computeKnownFPSignBit(Op0, Q) == false)
+    if (computeKnownFPSignBit(Op0, Q) == false) {
+      if (auto *Sel = dyn_cast<SelectInst>(Op0)) {
+        Value *T = Sel->getTrueValue();
+        Value *F = Sel->getFalseValue();
+        // Do not drop fabs around selects unless both arms are known non-negative.
+        if (!(computeKnownFPSignBit(T, Q) == false && computeKnownFPSignBit(F, Q) == false))
+          break;
+      }
       return Op0;
+    }
     break;
   case Intrinsic::bswap:
     // bswap(bswap(x)) -> x
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index d7a2ef722c84..06cd886f6494 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2906,17 +2906,16 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {

     if (match(Arg, m_Select(m_Value(Cond), m_Value(TVal), m_Value(FVal)))) {
       // fabs (select Cond, TrueC, FalseC) --> select Cond, AbsT, AbsF
-      if (Arg->hasOneUse() ? (isa<Constant>(TVal) || isa<Constant>(FVal))
-                           : (isa<Constant>(TVal) && isa<Constant>(FVal))) {
-        CallInst *AbsT = Builder.CreateCall(II->getCalledFunction(), {TVal});
-        CallInst *AbsF = Builder.CreateCall(II->getCalledFunction(), {FVal});
-        SelectInst *SI = SelectInst::Create(Cond, AbsT, AbsF);
-        FastMathFlags FMF1 = II->getFastMathFlags();
-        FastMathFlags FMF2 = cast<SelectInst>(Arg)->getFastMathFlags();
-        FMF2.setNoSignedZeros(false);
-        SI->setFastMathFlags(FMF1 | FMF2);
-        return SI;
-      }
+      {
+      CallInst *AbsT = Builder.CreateCall(II->getCalledFunction(), {TVal});
+      CallInst *AbsF = Builder.CreateCall(II->getCalledFunction(), {FVal});
+      SelectInst *SI = SelectInst::Create(Cond, AbsT, AbsF);
+      FastMathFlags FMF1 = II->getFastMathFlags();
+      FastMathFlags FMF2 = cast<SelectInst>(Arg)->getFastMathFlags();
+      FMF2.setNoSignedZeros(false);
+      SI->setFastMathFlags(FMF1 | FMF2);
+      return SI;
+    }
       // fabs (select Cond, -FVal, FVal) --> fabs FVal
       if (match(TVal, m_FNeg(m_Specific(FVal))))
         return replaceOperand(*II, 0, FVal);

